import hmac
import hashlib
import struct
import time
import base64
import io
import secrets
import qrcode
from urllib.parse import quote


class TOTPAuthenticator:
    def __init__(self, issuer_name="MyApp", digits=6, period=30, algorithm='sha1'):
        self.issuer_name = issuer_name
        self.digits = digits
        self.period = period
        self.algorithm = algorithm
        
    def generate_secret(self, length=32):
        random_bytes = secrets.token_bytes(length)
        secret = base64.b32encode(random_bytes).decode('utf-8')
        return secret.rstrip('=')
    
    def _get_hotp(self, secret, counter):
        key = base64.b32decode(secret + '=' * ((8 - len(secret)) % 8))
        
        counter_bytes = struct.pack('>Q', counter)
        
        if self.algorithm == 'sha1':
            hash_func = hashlib.sha1
        elif self.algorithm == 'sha256':
            hash_func = hashlib.sha256
        elif self.algorithm == 'sha512':
            hash_func = hashlib.sha512
        else:
            hash_func = hashlib.sha1
            
        hmac_hash = hmac.new(key, counter_bytes, hash_func).digest()
        
        offset = hmac_hash[-1] & 0x0F
        
        truncated_hash = struct.unpack('>I', hmac_hash[offset:offset+4])[0]
        truncated_hash &= 0x7FFFFFFF
        
        otp = truncated_hash % (10 ** self.digits)
        
        return str(otp).zfill(self.digits)
    
    def get_totp(self, secret, timestamp=None):
        if timestamp is None:
            timestamp = time.time()
        
        counter = int(timestamp) // self.period
        
        return self._get_hotp(secret, counter)
    
    def verify_totp(self, secret, token, timestamp=None, window=1):
        if timestamp is None:
            timestamp = time.time()
        
        current_counter = int(timestamp) // self.period
        
        for i in range(-window, window + 1):
            counter = current_counter + i
            expected_token = self._get_hotp(secret, counter)
            
            if hmac.compare_digest(expected_token, token):
                return True
        
        return False
    
    def get_provisioning_uri(self, secret, account_name, issuer=None):
        if issuer is None:
            issuer = self.issuer_name
        
        label = f"{issuer}:{account_name}"
        
        params = {
            'secret': secret,
            'issuer': issuer,
            'algorithm': self.algorithm.upper(),
            'digits': self.digits,
            'period': self.period
        }
        
        query_string = '&'.join([f"{k}={quote(str(v))}" for k, v in params.items()])
        
        uri = f"otpauth://totp/{quote(label)}?{query_string}"
        
        return uri
    
    def generate_qr_code(self, secret, account_name, issuer=None):
        uri = self.get_provisioning_uri(secret, account_name, issuer)
        
        qr = qrcode.QRCode(
            version=1,
            error_correction=qrcode.constants.ERROR_CORRECT_L,
            box_size=10,
            border=4,
        )
        qr.add_data(uri)
        qr.make(fit=True)
        
        img = qr.make_image(fill_color="black", back_color="white")
        
        return img
    
    def save_qr_code(self, secret, account_name, filename, issuer=None):
        img = self.generate_qr_code(secret, account_name, issuer)
        img.save(filename)
        return filename
    
    def get_qr_code_bytes(self, secret, account_name, issuer=None):
        img = self.generate_qr_code(secret, account_name, issuer)
        
        buffer = io.BytesIO()
        img.save(buffer, format='PNG')
        buffer.seek(0)
        
        return buffer.getvalue()


class UserTOTPManager:
    def __init__(self, issuer_name="MyApp"):
        self.authenticator = TOTPAuthenticator(issuer_name=issuer_name)
        self.users = {}
    
    def register_user(self, username, email=None):
        if username in self.users:
            raise ValueError(f"User {username} already registered")
        
        secret = self.authenticator.generate_secret()
        
        account_name = email if email else username
        
        self.users[username] = {
            'secret': secret,
            'account_name': account_name,
            'enabled': False,
            'backup_codes': self._generate_backup_codes()
        }
        
        return secret
    
    def _generate_backup_codes(self, count=10):
        codes = []
        for _ in range(count):
            code = ''.join([str(secrets.randbelow(10)) for _ in range(8)])
            codes.append(code)
        return codes
    
    def get_qr_code(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        return self.authenticator.generate_qr_code(
            user_data['secret'],
            user_data['account_name']
        )
    
    def get_provisioning_uri(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        return self.authenticator.get_provisioning_uri(
            user_data['secret'],
            user_data['account_name']
        )
    
    def enable_totp(self, username, verification_token):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        
        if self.authenticator.verify_totp(user_data['secret'], verification_token):
            user_data['enabled'] = True
            return True
        
        return False
    
    def verify_user_token(self, username, token):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        user_data = self.users[username]
        
        if not user_data['enabled']:
            raise ValueError(f"TOTP not enabled for user {username}")
        
        if token in user_data['backup_codes']:
            user_data['backup_codes'].remove(token)
            return True
        
        return self.authenticator.verify_totp(user_data['secret'], token)
    
    def disable_totp(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        self.users[username]['enabled'] = False
    
    def get_backup_codes(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        return self.users[username]['backup_codes'].copy()
    
    def regenerate_backup_codes(self, username):
        if username not in self.users:
            raise ValueError(f"User {username} not found")
        
        new_codes = self._generate_backup_codes()
        self.users[username]['backup_codes'] = new_codes
        return new_codes


